const handleAskMiron = () => {
    if (!contextMenu) return;

    const iframeDoc = iframeRef.current.contentDocument;
    const page = iframeDoc.querySelector('.page') || iframeDoc.body;
    const textContainer = iframeDoc.querySelector('.text-container') || page;

    const GAP_HEIGHT = 450;
    let splitY = contextMenu.nodeBottom; 
    let isBottomUp = splitY !== null;

    if (splitY === null) {
        splitY = contextMenu.rect.bottom + (iframeDoc.defaultView.scrollY || 0);
    }

    const currentH = parseInt(page.style.height || page.getAttribute('height') || page.clientHeight);
    page.style.height = (currentH + GAP_HEIGHT) + "px";
    contentDims.current.height = currentH + GAP_HEIGHT;

    const spans = textContainer.querySelectorAll('span, p, div.text-line');
    spans.forEach(span => {
        const bottomVal = parseInt(span.style.bottom);
        const topVal = parseInt(span.style.top);

        span.style.transition = 'bottom 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55), top 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55), transform 0.8s cubic-bezier(0.68, -0.55, 0.265, 1.55)';

        if (isBottomUp && !isNaN(bottomVal)) {
            if (bottomVal > splitY) {
                span.dataset.shifted = "true";
                span.style.bottom = (bottomVal + GAP_HEIGHT) + "px";
            }
        } else if (!isBottomUp && !isNaN(topVal)) {
            if (topVal > splitY) {
                span.dataset.shifted = "true";
                span.style.top = (topVal + GAP_HEIGHT) + "px";
            }
        } else if (!isBottomUp) {
            const spanAbsoluteTop = span.getBoundingClientRect().top + iframeDoc.defaultView.scrollY;
            if (spanAbsoluteTop > splitY) {
                span.dataset.shifted = "true";
                span.style.transform = `translateY(${GAP_HEIGHT}px)`;
            }
        }
    });

    const widgetContainer = iframeDoc.createElement('div');
    widgetContainer.className = 'in-book-widget-container';
    widgetContainer.style.position = 'absolute';
    widgetContainer.style.left = '0';
    widgetContainer.style.right = '0';
    widgetContainer.style.height = GAP_HEIGHT + 'px';
    widgetContainer.style.zIndex = '50';
    widgetContainer.style.opacity = '0';
    widgetContainer.style.transition = 'opacity 0.8s ease';
    widgetContainer.style.backgroundColor = '#080808';

    if (isBottomUp) {
        widgetContainer.style.bottom = splitY + 'px';
    } else {
        widgetContainer.style.top = splitY + 'px';
    }

    textContainer.appendChild(widgetContainer);

    setTimeout(() => { widgetContainer.style.opacity = '1'; }, 100);

    setInlineChat({
        container: widgetContainer,
        textContext: contextMenu.text
    });

    setContextMenu(null);
};

